# Parse components out of a resource ID using bash string splitting
RESOURCE_ID='/subscriptions/xxxxxxxx/resourceGroups/myapp-rg/providers/Microsoft.Compute/virtualMachines/myvm'

# Split by '/' into array
IFS='/' read -ra PARTS <<< "$RESOURCE_ID"

SUB_ID=${PARTS[2]}
RG_NAME=${PARTS[4]}
NAMESPACE=${PARTS[6]}
RESOURCE_TYPE=${PARTS[7]}
RESOURCE_NAME=${PARTS[8]}

echo "Subscription: $SUB_ID"
echo "Resource Group: $RG_NAME"
echo "Provider: $NAMESPACE/$RESOURCE_TYPE"
echo "Name: $RESOURCE_NAME"

# Using az resource show to parse any ID
az resource show --ids $RESOURCE_ID \
  --query '{name:name, type:type, rg:resourceGroup, sub:subscriptionId}'

// Bicep: construct a resource ID using resourceId() function

param subscriptionId string = subscription().subscriptionId
param rgName string = resourceGroup().name

// resourceId() builds the full ID for resources in the current RG
var vmId = resourceId('Microsoft.Compute/virtualMachines', 'myvm')

// For resources in a different subscription and/or RG:
var storageId = resourceId(
  subscriptionId,
  'other-rg',
  'Microsoft.Storage/storageAccounts',
  'sharedstorageacct'
)

// subscriptionResourceId() for subscription-scoped resources
var policyId = subscriptionResourceId(
  'Microsoft.Authorization/policyAssignments',
  'my-policy'
)

// tenantResourceId() for tenant-scoped resources (management groups)
var mgId = tenantResourceId(
  'Microsoft.Management/managementGroups',
  'my-management-group'
)

// ARM template: ID construction functions
{
  "$schema": "https://schema.management.azure.com/schemas/2019-04-01/deploymentTemplate.json#",
  "variables": {
    // resourceId() — same subscription, same RG
    "vmId": "[resourceId('Microsoft.Compute/virtualMachines', 'myvm')]",

    // resourceId() — different RG in same subscription
    "storageId": "[resourceId('other-rg', 'Microsoft.Storage/storageAccounts', 'mystore')]",

    // resourceId() — different subscription and RG
    "crossSubId": "[resourceId(parameters('subId'), 'other-rg', 'Microsoft.Storage/storageAccounts', 'mystore')]",

    // subscriptionResourceId() — subscription scope
    "roleAssignmentId": "[subscriptionResourceId('Microsoft.Authorization/roleAssignments', parameters('raGuid'))]",

    // concat() approach (older templates)
    "manualId": "[concat('/subscriptions/', subscription().subscriptionId, '/resourceGroups/', resourceGroup().name, '/providers/Microsoft.Compute/virtualMachines/myvm')]"
  }
}

# Terraform: access and construct resource IDs

resource "azurerm_virtual_machine" "myvm" {
  name                = "myvm"
  resource_group_name = azurerm_resource_group.myapp.name
  location            = azurerm_resource_group.myapp.location
  # ...
}

# Access the full resource ID after creation
output "vm_id" {
  value = azurerm_virtual_machine.myvm.id
}

# Use an existing resource's ID without managing it
data "azurerm_virtual_machine" "existing_vm" {
  name                = "existing-vm"
  resource_group_name = "existing-rg"
}

output "existing_vm_id" {
  value = data.azurerm_virtual_machine.existing_vm.id
}

# Construct an ID without a data source (when you know the pattern)
locals {
  manual_id = "/subscriptions/${var.subscription_id}/resourceGroups/${var.rg_name}/providers/Microsoft.Compute/virtualMachines/${var.vm_name}"
}
